var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트 베르너…….","JPN":"リヒャルト・ベルナー……","ENG":"Richard Werner...","TWN":"理查·韋爾納……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"다음 회의에서 보자고 했던 말이 무색할 정도로, 일찍 만나게 됐네.","JPN":"次の会議で会おうという言葉が、思いのほか早く実現してしまったな。","ENG":"We met much earlier than we mentioned about the next meeting.","TWN":"說好下次會議再見，沒想到會這麼快。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"물론, 이런 식으로 재회하게 될 줄은 몰랐지만…….","JPN":"だけど、まさかこんな再会になるなんて……","ENG":"Of course, I didn't expect to meet you like this here, but...","TWN":"當然，還是以這種方式……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"섬뜩할 정도로 기묘한 사건이야.","JPN":"恐ろしいほどに奇妙な事件だ。","ENG":"This case is frighteningly strange.","TWN":"這次的事件相當詭異。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"현장은 밀실에……. 목이 잘린 시체에서는 피 한 방울 흐르지 않았어.","JPN":"現場は密室……首を取られた死体からは血液が一滴も流れていない。","ENG":"The scene was closed off... and there wasn't even a single drop of blood from the headless corpse.","TWN":"現場是密室……被斬首的屍體沒有流出一滴血。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"마치, 이 방에서 오직 머리만 다른 공간으로 날아가 버린 것 같아.","JPN":"まるで、この部屋で頭部だけが違う空間へと飛ばされてしまったようだ。","ENG":"It's as if his head was transported to another space.","TWN":"就好像，只有頭顱從這個房間飛到了另一個空間。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"게다가 이 낙서…….","JPN":"それに、この落書き……","ENG":"And this writing...","TWN":"而且這個筆跡……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>네 번째 시련을 지나라, 그녀는 불꽃에 달궈진 철이 될지니.</color>","JPN":"<color=#ffd34c>四つ目の試練を越えろ、彼女は炎で煉られた鉄になるだろう。</color>","ENG":"<color=#ffd34c>Pass the fourth ordeal, and she will become iron heated in flame.</color>","TWN":"<color=#ffd34c>經歷第四之裁判，她將會是淬火的鐵。</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.</color>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>行汝欲行之事，此為律法之全部。</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이게 대체 무슨 의미야?","JPN":"これはいったいどういうことだ？","ENG":"What does it even mean?","TWN":"這到底是什麼意思？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어 님! 찾았습니다!","JPN":"シニア！　見つけました！","ENG":"We found it, ma'am!","TWN":"Senior！找到了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"유력한 용의자! 용의자를 찾았습니다!","JPN":"有力な容疑者！　容疑者を見つけたのです！","ENG":"The prime suspect! We found the prime suspect!","TWN":"最重要的嫌疑人！找到嫌疑人了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐라고? 어디서?","JPN":"何だと？　どこでだ？","ENG":"What? Where?","TWN":"什麼？哪裡？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"드라마에서요!","JPN":"ドラマでです！","ENG":"From the drama series!","TWN":"在肥皂劇裡！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"방금 마지막 에피소드를 마친 드라마에서 낙서의 의미가 밝혀졌습니다.","JPN":"ちょうど最後のエピソードが終わったドラマで、落書きの意味が判明しました。","ENG":"It just aired its last episode and the meaning of the writing was revealed.","TWN":"剛剛結束的最後一集電視劇裡，揭示了塗鴉的意義！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"틀림없어요! 유력한 용의자는 스완!","JPN":"間違いありません！　有力な容疑者はスワン！","ENG":"It's without a doubt! Our prime suspect is Swan!","TWN":"沒錯！最有嫌疑的人是史旺！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"샤레이드의 영화 배우이자, 각본가인 스완 클레어가 벌인 짓입니다!","JPN":"シャレードの映画女優であり、脚本家のスワン・クレアの仕業です！","ENG":"Swan Claire, Charade's movie actress and scriptwriter, is behind all of this!","TWN":"這是查雷德的電影演員兼編劇史旺·克萊爾幹的好事！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 드라마?","JPN":"はあ？　ドラマ？","ENG":"What? Drama series?","TWN":"什麼……？電視劇？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"나랑 지금 장난해? 무슨 잠꼬대 같은 소리야!?","JPN":"ふざけてるのか？　何を寝ぼけたことを！？","ENG":"Are you kidding me? What kind of nonsense is that?!","TWN":"你在和我開玩笑嗎？這是什麼夢話！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"존재해선 안 될 악취가… 느껴지는구나.","JPN":"存在してはいけない悪臭が……感じられるな。","ENG":"I sense the stench... that should not exist.","TWN":"我聞到了一股……不應該有的惡臭。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 땅에도… 종말이 도래하려는 것인가.","JPN":"この地にも……終末が到来するのか。","ENG":"Will this realm... reach the apocalypse as well?","TWN":"末日……就要臨到這片土地了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그때처럼…","JPN":"あの時のように……","ENG":"Like that time…","TWN":"就像那時……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"커억… 크허헉…","JPN":"がはっ……くうっ……","ENG":"Kgh... Khhhk...","TWN":"咳……咳咳……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GATE_NPC_CHARADE_NULL","text":{"KOREA":"섹터E7. 방금 침입센서가 작동했던데, 무슨 일이지?","JPN":"セクターE7。今侵入センサーが作動したが、どうした？","ENG":"Sector E7. We noticed the intruder alert go off just now. What's going on?","TWN":"E7防區，入侵感測器剛剛響了。怎麼回事？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"…별일 아니었습니다.","JPN":"……大したことではありませんでした。","ENG":"...It was nothing.","TWN":"……沒什麼。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"산짐승이 내부로 들어오려 해서… <color=#ff3636>잡았습니다.</color>","JPN":"獣が内部に入ろうとしていたので……<color=#ff3636>倒しました</color>。","ENG":"A wild animal was trying to come in... so I <color=#ff3636>handled it.</color>","TWN":"有一隻野獸試圖鑽進去……<color=#ff3636>已經被我抓到了。</color>"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GATE_NPC_CHARADE_NULL","text":{"KOREA":"그런가.","JPN":"そうか。","ENG":"I see.","TWN":"是嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GATE_NPC_CHARADE_NULL","text":{"KOREA":"침식지대에서 왔을 확률이 높으니 최대한 빨리 소각하도록.","JPN":"侵食地帯から来た確率が高いから、なるべく早く焼却しろ。","ENG":"It's likely from a Corrupted area. Dispose of it as soon as possible.","TWN":"牠有可能來自侵蝕地區，儘快處理掉。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"이어받았다. 동포의 정보.","JPN":"受ケ継イダ。仲間ノ、情報。","ENG":"I received. Information from my kind.","TWN":"收到了。同類的資訊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"개발 부지. 섹터 E7 F-23. 그곳에 잠들어 있다.","JPN":"開発地。セクターE7、F-23。アソコニ眠ッテイル。","ENG":"Development site. Sector E7 F-23. It is there.","TWN":"開發用地。E7，F-23區。那裡沉睡著。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>특별한 가능성.</color>","JPN":"<color=#ffd34c>特別ナ可能性。</color>","ENG":"The <color=#ffd34c>special possibilities</color>.","TWN":"<color=#ffd34c>特別的可能性。</color>"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color>","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Lotus</color>","TWN":"管理局直轄市<color=#ffd34c>洛德斯</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금쯤이면, 슬슬 블랙 네트워크에 의뢰했던 사진이 샤레이드 전역에 퍼졌겠군요.","JPN":"もうそろそろ、ブラックネットワークに依頼した写真がシャレード全域に広まる頃でしょう。","ENG":"The photo I requested on the Dark Network should have spread all over Charade by now.","TWN":"現在，委託給黑色網路的照片應該已經傳遍了查雷德全境吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"특종을 잡은 언론은 제멋대로 떠들어대고, 권력자들은 책임을 회피하기 급급하며…….","JPN":"特ダネを掴んだマスコミは勝手に触れまわり、権力者は責任を逃れることに夢中で……","ENG":"The media will be busy with the scoop, and the authorities will be busy trying to avoid any responsibility...","TWN":"抓到獨家新聞的媒體恣意喧囂，當權者們急於推卸責任……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"공포에 휩싸인 시민들은 물어뜯을 누군가를 찾고 있겠죠.","JPN":"恐怖に囚われた市民は不満をぶつける相手を探していることでしょう。","ENG":"Also, fearful citizens will try to find someone to blame it on.","TWN":"以及，陷入恐懼的市民們開始尋找可以撕咬的物件。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저를 추적해 온 걸 보면, 지금껏 제가 드라마 속에 남긴 힌트를 눈치챈 것 같은데.","JPN":"私を追跡してきたということは、今まで私がドラマの中に残したヒントに気付いたようですが。","ENG":"Judging by how you're after me, it seems that you have noticed the hints I left in the series.","TWN":"一路追蹤到這裡，看來你們已經發現了我在劇中留下的線索。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"감상을 듣고 싶네요.","JPN":"感想をお聞きしたいですね。","ENG":"Now, I'd like to hear your thoughts.","TWN":"有什麼感想嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어떤가요, 제가 만들어낸 이 상황과 드라마 속의 장면…….","JPN":"いかがですか？　私が作り出したこのシチュエーションとドラマのシーンは……","ENG":"How is it? The situation I created and also the scene in the series.","TWN":"怎麼樣，我創造的這個情景和電視劇中的場面……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"똑같지 않나요?","JPN":"同じではないですか？","ENG":"Aren't they the same?","TWN":"是不是一模一樣？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_SWANSONG_NPC_ELITE","text":{"KOREA":"똑같지 않냐고? 완전히 미쳤군.","JPN":"同じだと？　完全にいかれてやがる。","ENG":"The same? You're crazy.","TWN":"一樣嗎？……你完全瘋了啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_SWANSONG_NPC_ELITE","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L31_1","type":"dialog","speaker":"RIFLE_SWANSONG_NPC_ELITE","text":{"KOREA":"스완 클레어! 넌 포위됐다! 도주를 멈추고 이제 그만 포기해!","JPN":"スワン・クレア！　お前は包囲されている！　逃走は諦めて、大人しく投降するんだ！","ENG":"Swan Claire! You're surrounded! Stop running and surrender!","TWN":"史旺·克萊爾！你被包圍了！停止逃跑，現在放棄還不遲！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_SWANSONG_NPC_ELITE","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"미쳤다라…….","JPN":"いかれてる、ですか……","ENG":"Crazy, you say...","TWN":"瘋……了嗎。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 저는 아주 오래전에 미쳐버렸을지도 모르죠.","JPN":"そうですね。私はとっくにいかれていたのかもしれません。","ENG":"Yes. Perhaps I've gone insane a long time ago.","TWN":"是啊，我可能很久以前就已經瘋了吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.<color=#ffd34c>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>行汝欲行之事，此為律法之全部。<color=#ffd34c>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 단 하나의 <color=#ffd34c>바람</color>에 미쳐 있지 않았다면, 지금까지 버틸 수조차 없었을 테니까.","JPN":"いかれるくらい、そのたった一つの<color=#ffd34c>望み</color>を成そうとしていなかったら、今まで耐えることすらできなかったはずですから。","ENG":"If I hadn't gone insane about this one <color=#ffd34c>wish</color>, I wouldn't have been able to endure it.","TWN":"如果不是因為那唯一的<color=#ffd34c>願望</color>，我根本撐不到現在。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIFLE_SWANSONG_NPC_ELITE","text":{"KOREA":"바람이라고?","JPN":"望みだと？","ENG":"Wish?","TWN":"願望？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_SWANSONG_NPC_ELITE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIFLE_SWANSONG_NPC_ELITE","text":{"KOREA":"커헉……!!","JPN":"くはっ……！！","ENG":"Kuh...!!","TWN":"咳呃……！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_SWANSONG_NPC_ELITE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIFLE_SWANSONG_NPC_ELITE","text":{"KOREA":"우산을 순식간에 칼로 바꿨어!!","JPN":"傘が一瞬で刀になったぞ！！","ENG":"Her umbrella suddenly transformed into a sword!!","TWN":"那把傘能變成刀！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_SWANSONG_NPC_ELITE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_SWANSONG_NPC_ELITE","text":{"KOREA":"조심해! 능력을 모르는 이상, 섣불리 접근하지 마!","JPN":"気をつけろ！　能力がわからない以上、むやみに近づくな！","ENG":"Be careful! We don't know her powers, so don't approach her carelessly!","TWN":"小心！在不了解能力的情況下，不要輕易靠近！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SWANSONG_NPC_ELITE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"각본가로서 아쉽게 생각하고 있답니다.","JPN":"脚本家として残念に思っています。","ENG":"I feel sorry as a scriptwriter.","TWN":"作為編劇，我感到很遺憾。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"연속극이 종영해버려서 관객들은 영영 <color=#ffd34c>진짜 결말</color>을 알 수 없겠죠.","JPN":"連続ドラマの撮影が終了して、観客たちは永遠に<color=#ffd34c>本当の結末</color>を知らないのですから。","ENG":"With the end of the drama series, the audience will never know the <color=#ffd34c>true ending</color>.","TWN":"連續劇結束了，觀眾們永遠也無法知道<color=#ffd34c>真正的結局</color>了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"하지만 걱정할 필요 없어요.","JPN":"ですが、心配する必要はありません。","ENG":"But there's nothing to worry.","TWN":"不過別擔心。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"앞으로 한 걸음.","JPN":"あと一歩。","ENG":"Just one more step forward.","TWN":"請繼續向前邁進吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"그 한 걸음의 끝에, 이 세계 모든 이들이 알게 될 테니까요.","JPN":"その一歩を進めば、この世の全人類が知ることになるでしょうから。","ENG":"With that, the entire world will know.","TWN":"在那一步的盡頭，全世界的人都會知道。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"제가 준비한. 그리고 우리 세계가 맞이했던 진짜 결말을.","JPN":"私が用意した、そして、私たちの世界が迎えた本当の結末を。","ENG":"What I prepared... as the true ending for this world.","TWN":"我所準備的，以及這個世界所迎來的真正結局。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};